import React, { useState } from 'react';
import { Carousel } from 'react-bootstrap';
import CollapsedText from './CollapsedText';

function SimpleCarousel({ images }) {
    const [showDetails, setShowDetails] = useState(true);
    const isSmallScreen = window.innerWidth < 768;

    return (
        <Carousel data-bs-theme="dark" indicators={!isSmallScreen}>
            {images.map((image, index) => (
                <Carousel.Item key={index} className='carouselItem'>
                    <img
                        className="d-block w-100"
                        src={image.src}
                        alt={image.title}
                    />
                    <Carousel.Caption className={isSmallScreen ? 'd-none' : ''}>
                        {showDetails ? (
                            <>
                                <h5>{image.title}</h5>
                                <p>{image.description}</p>
                            </>
                        ) : (
                            <CollapsedText name={image.title} text={image.description} maxLines={3} />
                        )}
                    </Carousel.Caption>
                </Carousel.Item>
            ))}
        </Carousel>
    );
}

export default SimpleCarousel;
